private void xrTableCell180_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    var femalesTrans = Convert.ToDecimal(GetCurrentColumnValue("FemalesTrans"));
    var femalesDepleted = Convert.ToDecimal(GetCurrentColumnValue("FemalesDepleted"));

    if (femalesTrans != 0)
        ((XRTableCell)sender).Text = ((femalesDepleted / femalesTrans) * 100).ToString("N2");
    else
        ((XRTableCell)sender).Text = "N2";
}

