private void xrTableCell118_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    // Read POL
    decimal pol = GetCurrentColumnValue("POL") != null
        ? Convert.ToDecimal(GetCurrentColumnValue("POL"))
        : 0;

    // Read TotalEggSold (from global variable "total")
    decimal totalEggSold = total;  // <--- as you said, global from another script

    // Compute CumHatchability
    decimal settedEggs = GetCurrentColumnValue("SettedEggs") != null
        ? Convert.ToDecimal(GetCurrentColumnValue("SettedEggs"))
        : 0;
    decimal selChicks = GetCurrentColumnValue("SelChicks") != null
        ? Convert.ToDecimal(GetCurrentColumnValue("SelChicks"))
        : 0;
    decimal cullsChicks = GetCurrentColumnValue("CullsChicks") != null
        ? Convert.ToDecimal(GetCurrentColumnValue("CullsChicks"))
        : 0;
    decimal deadChicks = GetCurrentColumnValue("DeadChicks") != null
        ? Convert.ToDecimal(GetCurrentColumnValue("DeadChicks"))
        : 0;

    decimal cumHatchability = (settedEggs != 0)
        ? ((selChicks + cullsChicks + deadChicks) / settedEggs) * 100
        : 0;

    // Compute EstChicks_PerEgg
    decimal estChicksPerEgg = (totalEggSold != 0 && cumHatchability != 0)
        ? (totalEggSold * cumHatchability / 100)
        : 0;

    // Final formula: divide by POL
    decimal result = (pol != 0) ? (estChicksPerEgg / pol) : 0;

    // Assign result
    ((XRTableCell)sender).Text = result.ToString("0.00");
}

private void xrTableCell124_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    // --- POL ---
    decimal pol = GetCurrentColumnValue("POL") != null
        ? Convert.ToDecimal(GetCurrentColumnValue("POL"))
        : 0;

    // --- BalOfHatEggs = FarmInTake - Total_RejEggs ---
    decimal farmInTake = GetCurrentColumnValue("FarmInTake") != null
        ? Convert.ToDecimal(GetCurrentColumnValue("FarmInTake"))
        : 0;

    decimal rejEggs = 0;
    decimal rejBroken = GetCurrentColumnValue("RejBroken") != null ? Convert.ToDecimal(GetCurrentColumnValue("RejBroken")) : 0;
    decimal rejCrack  = GetCurrentColumnValue("RejCrack")  != null ? Convert.ToDecimal(GetCurrentColumnValue("RejCrack"))  : 0;
    decimal rejDef    = GetCurrentColumnValue("RejDef")    != null ? Convert.ToDecimal(GetCurrentColumnValue("RejDef"))    : 0;
    decimal rejOther  = GetCurrentColumnValue("RejOther")  != null ? Convert.ToDecimal(GetCurrentColumnValue("RejOther"))  : 0;
    rejEggs = rejBroken + rejCrack + rejDef + rejOther;

    decimal balOfHatEggs = farmInTake - rejEggs;

    // --- TotalEggSold (global from another script) ---
    decimal totalEggSold = total;

    // --- StockHatEggBal ---
    decimal settedEggs = GetCurrentColumnValue("SR_HT_FlkSumProdReport.SettedEggs") != null
        ? Convert.ToDecimal(GetCurrentColumnValue("SR_HT_FlkSumProdReport.SettedEggs"))
        : 0;

    decimal stockHatEggBal = balOfHatEggs - (settedEggs + totalEggSold);

    // --- ActHatchBalanceEggs ---
    decimal setEggBalHatEgg = GetCurrentColumnValue("SetEggBalHatEgg") != null
        ? Convert.ToDecimal(GetCurrentColumnValue("SetEggBalHatEgg"))
        : 0;
    decimal selChickBal = GetCurrentColumnValue("SelChickBalHatEgg") != null
        ? Convert.ToDecimal(GetCurrentColumnValue("SelChickBalHatEgg"))
        : 0;
    decimal cullsBal = GetCurrentColumnValue("CullsBalHatEgg") != null
        ? Convert.ToDecimal(GetCurrentColumnValue("CullsBalHatEgg"))
        : 0;
    decimal deadsBal = GetCurrentColumnValue("DeadsBalHatEgg") != null
        ? Convert.ToDecimal(GetCurrentColumnValue("DeadsBalHatEgg"))
        : 0;

    decimal actHatchBalanceEggs = (setEggBalHatEgg != 0)
        ? ((selChickBal + cullsBal + deadsBal) / setEggBalHatEgg) * 100
        : 0;

    // --- ESTChicks_PerStock_HE ---
    decimal estChicksPerStockHE = (stockHatEggBal != 0 && actHatchBalanceEggs != 0)
        ? (stockHatEggBal * actHatchBalanceEggs / 100)
        : 0;

    // --- Final Result ---
    decimal result = (pol != 0) ? (estChicksPerStockHE / pol) : 0;

    // --- Assign to cell ---
    ((XRTableCell)sender).Text = result.ToString("0.00");
}

