    decimal rejOther  = GetCurrentColumnValue("RejOther")  != null ? Convert.ToDecimal(GetCurrentColumnValue("RejOther"))  : 0;

    decimal balOfHatEggs = farmInTake - (rejBroken + rejCrack + rejDef + rejOther);

    // --- TotalEggSold (already global) ---
    decimal totalEggSold = total;

    // --- Setted Eggs ---
    decimal settedEggs = GetCurrentColumnValue("SR_HT_FlkSumProdReport.SettedEggs") != null
        ? Convert.ToDecimal(GetCurrentColumnValue("SR_HT_FlkSumProdReport.SettedEggs"))
        : 0;

    // --- CumHatchability ---
    decimal selChicks  = GetCurrentColumnValue("SR_HT_FlkSumProdReport.SelChicks") != null ? Convert.ToDecimal(GetCurrentColumnValue("SR_HT_FlkSumProdReport.SelChicks")) : 0;
    decimal cullsChicks= GetCurrentColumnValue("SR_HT_FlkSumProdReport.CullsChicks") != null ? Convert.ToDecimal(GetCurrentColumnValue("SR_HT_FlkSumProdReport.CullsChicks")) : 0;
    decimal deadChicks = GetCurrentColumnValue("SR_HT_FlkSumProdReport.DeadChicks") != null ? Convert.ToDecimal(GetCurrentColumnValue("SR_HT_FlkSumProdReport.DeadChicks")) : 0;

    decimal cumHatchability = (settedEggs != 0)
        ? ((selChicks + cullsChicks + deadChicks) / settedEggs) * 100
        : 0;

    // --- EstChicks_PerEgg ---
    decimal estChicksPerEgg = (totalEggSold != 0 && cumHatchability != 0)
        ? (totalEggSold * cumHatchability / 100)
        : 0;

    // --- StockHatEggBal ---
    decimal stockHatEggBal = balOfHatEggs - (settedEggs + totalEggSold);

    // --- ActHatchBalanceEggs ---
    decimal setEggBalHatEgg = GetCurrentColumnValue("SetEggBalHatEgg") != null
        ? Convert.ToDecimal(GetCurrentColumnValue("SetEggBalHatEgg"))
        : 0;
    decimal selChickBal = GetCurrentColumnValue("SelChickBalHatEgg") != null ? Convert.ToDecimal(GetCurrentColumnValue("SelChickBalHatEgg")) : 0;
    decimal cullsBal    = GetCurrentColumnValue("CullsBalHatEgg") != null ? Convert.ToDecimal(GetCurrentColumnValue("CullsBalHatEgg")) : 0;
    decimal deadsBal    = GetCurrentColumnValue("DeadsBalHatEgg") != null ? Convert.ToDecimal(GetCurrentColumnValue("DeadsBalHatEgg")) : 0;

    decimal actHatchBalanceEggs = (setEggBalHatEgg != 0)
        ? ((selChickBal + cullsBal + deadsBal) / setEggBalHatEgg) * 100
        : 0;

    // --- ESTChicks_PerStock_HE ---
    decimal estChicksPerStockHE = (stockHatEggBal != 0 && actHatchBalanceEggs != 0)
        ? (stockHatEggBal * actHatchBalanceEggs / 100)
        : 0;

    // --- CumChicks (direct column) ---
    decimal cumChicks = GetCurrentColumnValue("CumChicks") != null
        ? Convert.ToDecimal(GetCurrentColumnValue("CumChicks"))
        : 0;

    // --- CumChicks_Act_Est ---
    decimal cumChicksActEst = estChicksPerEgg + estChicksPerStockHE + cumChicks;

    // --- Final Result ---
    decimal result = (pol != 0) ? (cumChicksActEst / pol) : 0;

    // --- Assign to cell ---
    ((XRTableCell)sender).Text = result.ToString("0.00");
}

