private void xrTableCell187_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
      decimal result = 0;

    // ------------------ EstChicks_PerEgg ------------------
    decimal estChicks_PerEgg = 0;
    decimal cumHatchability = 0;

    object valSetted = GetCurrentColumnValue("SettedEggs");
    if (valSetted != null && decimal.TryParse(valSetted.ToString(), out decimal settedEggs) && settedEggs != 0)
    {
        // Sel + Culls + Deads
        decimal sel = 0, culls = 0, dead = 0;

        if (decimal.TryParse(GetCurrentColumnValue("SelChicks")?.ToString(), out decimal tempSel)) sel = tempSel;
        if (decimal.TryParse(GetCurrentColumnValue("CullsChicks")?.ToString(), out decimal tempCulls)) culls = tempCulls;
        if (decimal.TryParse(GetCurrentColumnValue("DeadChicks")?.ToString(), out decimal tempDead)) dead = tempDead;

        cumHatchability = (sel + culls + dead) / settedEggs * 100;
    }

    // use global "total" for TotalEggSold
    estChicks_PerEgg = total * cumHatchability / 100;

    // ------------------ ESTChicks_PerStock_HE ------------------
    decimal estChicks_PerStock_HE = 0;

    if (decimal.TryParse(GetCurrentColumnValue("StockHatEggBal")?.ToString(), out decimal stockBal) && stockBal != 0)
    {
        // Calculate ActHatchBalanceEggs
        decimal actHatchBalanceEggs = 0;
        if (decimal.TryParse(GetCurrentColumnValue("SetEggBalHatEgg")?.ToString(), out decimal setEggBal) && setEggBal != 0)
        {
            decimal selBal = 0, cullsBal = 0, deadBal = 0;

            if (decimal.TryParse(GetCurrentColumnValue("SelChickBalHatEgg")?.ToString(), out decimal tempSelBal)) selBal = tempSelBal;
            if (decimal.TryParse(GetCurrentColumnValue("CullsBalHatEgg")?.ToString(), out decimal tempCullsBal)) cullsBal = tempCullsBal;
            if (decimal.TryParse(GetCurrentColumnValue("DeadsBalHatEgg")?.ToString(), out decimal tempDeadBal)) deadBal = tempDeadBal;

            actHatchBalanceEggs = (selBal + cullsBal + deadBal) / setEggBal * 100;
        }

        estChicks_PerStock_HE = stockBal * actHatchBalanceEggs / 100;
    }

    // ------------------ CumChicks ------------------
    decimal cumChicks = 0;
    if (decimal.TryParse(GetCurrentColumnValue("CumChicks")?.ToString(), out decimal tempCum))
        cumChicks = tempCum;

    // ------------------ Final Equation ------------------
    result = estChicks_PerEgg + estChicks_PerStock_HE + cumChicks;

    // Assign to cell
    XRTableCell cell = sender as XRTableCell;
    cell.Text = result.ToString("0.##");

}

